        { name: "Chaa Meang", time: "20 mins", region: "National", img: "./images/kh/meang.png", ingredients: ["Yellow wheat noodles", "Beef", "Chinese broccoli", "Egg", "Dark soy sauce"], instructions: ["Stir-fry beef and Chinese broccoli in a wok.", "Add yellow noodles and season with dark soy sauce and oyster sauce.", "Push noodles to the side and scramble an egg in the center.", "Toss everything together until the noodles are slightly charred."] },
        { name: "Tuk Prahok", time: "15 mins", region: "National", img: "./images/kh/prahok.png", ingredients: ["Prahok", "Lime juice", "Lemongrass", "Eggplant", "Grilled beef"], instructions: ["Whisk fermented fish paste with lime juice, warm water, and sugar.", "Add finely sliced lemongrass, kaffir lime leaves, and pea eggplants.", "Slice rare-grilled beef into thin strips.", "Serve the beef and raw vegetables with the Prahok mixture as a dip."] },
        { name: "Nom Lort", time: "20 mins", region: "National", img: "./images/kh/lort.png", ingredients: ["Rice flour", "Pandan leaf juice", "Coconut milk", "Palm sugar", "Salt"], instructions: ["Mix rice flour with pandan juice and cook until thick and jelly-like.", "Press the hot dough through a sieve into cold water to form 'worms'.", "Prepare a sauce by simmering palm sugar with water and a pinch of salt.", "Serve the green jelly worms in a bowl with coconut milk and sugar syrup."] }
